import React, { useState } from 'react';
import Header from './components/Header';
import GlobalNav from './components/GlobalNav';
import SectionGoals from './components/sections/SectionGoals';
import SectionProducts from './components/sections/SectionProducts';
import SectionStructure from './components/sections/SectionStructure';
import SectionHooks from './components/sections/SectionHooks';
import SectionBrand from './components/sections/SectionBrand';
import SectionMultiColor from './components/sections/SectionMultiColor';
import { ActiveSection, CampaignSeason } from './types';
import { CAMPAIGN_DATA } from './data';

const App: React.FC = () => {
  const [activeSeason, setActiveSeason] = useState<CampaignSeason>('SS26');
  const [activeSection, setActiveSection] = useState<ActiveSection>('home');

  const currentData = activeSeason === 'SS26' ? CAMPAIGN_DATA.multiColor : CAMPAIGN_DATA.singleColor;

  const handleNextSection = (next: ActiveSection) => {
    setActiveSection(next);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const renderSection = () => {
    switch (activeSection) {
      case 'goals': 
        return <SectionGoals data={currentData.goals} onBack={() => setActiveSection('home')} onNext={() => handleNextSection('products')} />;
      case 'products': 
        return <SectionProducts onBack={() => setActiveSection('home')} onNext={() => handleNextSection('structure')} products={currentData.products} />;
      case 'structure': 
        return <SectionStructure data={currentData.shootingGuide} onBack={() => setActiveSection('home')} onNext={() => handleNextSection('hooks')} />;
      case 'hooks': 
        return <SectionHooks data={currentData.hooks} onBack={() => setActiveSection('home')} onNext={() => handleNextSection('brand')} />;
      case 'brand': 
        return <SectionBrand onBack={() => setActiveSection('home')} />;
      case 'multicolor':
        return <SectionMultiColor onBack={() => setActiveSection('home')} onNext={() => handleNextSection('structure')} />;
      default: return (
        <div className="animate-slide-up">
          {/* Shortened Hero Section - 50vh */}
          <div className="relative h-[50vh] w-full overflow-hidden bg-brand-dark">
            <img 
              src={currentData.heroImage} 
              className="absolute inset-0 w-full h-full object-cover opacity-70"
              alt="COSY ISLAND Campaign"
            />
            <div className="absolute inset-0 bg-gradient-to-b from-transparent via-brand-dark/20 to-brand-dark/60"></div>
            <div className="absolute inset-0 flex flex-col justify-center items-center text-center px-6 pt-12">
              <span className="text-brand-secondary font-bold tracking-[0.4em] uppercase text-[10px] mb-4">
                {currentData.label}
              </span>
              <h1 className="text-5xl md:text-7xl font-brand text-white mb-6">COSY ISLAND</h1>
              <p className="text-white/80 max-w-xl mx-auto text-lg font-light italic leading-relaxed">
                {currentData.description}
              </p>
              <div className="mt-8">
                <button 
                  onClick={() => setActiveSection('goals')}
                  className="bg-brand-primary text-white px-10 py-3.5 rounded-full font-bold text-xs hover:bg-brand-secondary transition-all transform hover:-translate-y-1 shadow-2xl"
                >
                  Explore Briefing
                </button>
              </div>
            </div>
          </div>

          {/* Quick Nav Grid */}
          <div className="max-w-7xl mx-auto px-6 py-16 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            <SectionCard num="01" title="Goals & Flow" subtitle="Requirements" onClick={() => setActiveSection('goals')} />
            <SectionCard num="02" title="The Collection" subtitle="Product Choice" onClick={() => setActiveSection('products')} />
            {activeSeason === 'SS26' && (
              <SectionCard num="03" title="Multi-Color Format" subtitle="Special Guide" onClick={() => setActiveSection('multicolor')} />
            )}
            <SectionCard num="04" title="Shooting Guide" subtitle="Video Structure" onClick={() => setActiveSection('structure')} />
            <SectionCard num="05" title="Inspiration" subtitle="Hook Ideas" onClick={() => setActiveSection('hooks')} />
            <SectionCard num="06" title="Our Story" subtitle="Brand Identity" onClick={() => setActiveSection('brand')} />
          </div>
        </div>
      );
    }
  };

  return (
    <div className="min-h-screen">
      <Header 
        season={activeSeason} 
        onSeasonChange={(s) => { setActiveSeason(s); setActiveSection('home'); }} 
        onHome={() => setActiveSection('home')}
      />

      {activeSection !== 'home' && (
        <GlobalNav active={activeSection} onNavigate={setActiveSection} isMultiColor={activeSeason === 'SS26'} />
      )}

      <main>
        {renderSection()}
      </main>

      <footer className="bg-brand-dark text-white py-16 border-t border-white/5">
        <div className="container mx-auto text-center px-6">
          <h2 className="text-3xl font-brand mb-8 tracking-tighter">COSY ISLAND</h2>
          <div className="flex flex-col md:flex-row justify-center gap-4 md:gap-12 text-[9px] font-bold uppercase tracking-[0.3em] text-white/30">
            <span>Cosy with an 'S'</span>
            <span>Effortless Comfort</span>
            <span>{CAMPAIGN_DATA.common.website}</span>
          </div>
          <p className="mt-12 text-white/10 text-[9px] uppercase tracking-widest">© 2026 COSY ISLAND Official</p>
        </div>
      </footer>
    </div>
  );
};

const SectionCard: React.FC<{ num: string; title: string; subtitle: string; onClick: () => void }> = ({ num, title, subtitle, onClick }) => (
  <div 
    onClick={onClick}
    className="group bg-white p-10 border border-brand-primary/5 hover:border-brand-primary/20 transition-all cursor-pointer shadow-sm hover:shadow-xl relative overflow-hidden flex flex-col justify-between h-64 rounded-2xl"
  >
    <span className="absolute -top-4 -right-4 text-brand-primary/5 text-8xl font-serif group-hover:text-brand-primary/10 transition-colors">{num}</span>
    <div className="relative z-10">
      <h3 className="text-2xl font-serif text-brand-primary mb-2">{title}</h3>
      <p className="text-slate-400 text-[10px] tracking-widest uppercase font-bold">{subtitle}</p>
    </div>
    <div className="relative z-10 flex items-center text-brand-primary font-bold text-[10px] tracking-widest">
      View <i className="fas fa-arrow-right ml-2 group-hover:translate-x-1 transition-transform"></i>
    </div>
  </div>
);

export default App;

import React, { useState } from 'react';

interface Product {
  id: string;
  name: string;
  colors: string[];
  image: string;
  url: string;
  sellingPoints: string[];
}

interface SectionProductsProps {
  onBack: () => void;
  onNext: () => void;
  products: Product[];
}

const SectionProducts: React.FC<SectionProductsProps> = ({ onBack, onNext, products }) => {
  const [selected, setSelected] = useState<Product | null>(null);

  return (
    <div className="max-w-7xl mx-auto px-6 py-20 animate-slide-up">
      <div className="flex justify-between items-center mb-16">
        <button onClick={onBack} className="text-brand-primary/50 hover:text-brand-primary font-bold text-[10px] tracking-widest transition-all">
          <i className="fas fa-arrow-left mr-2"></i> HOME
        </button>
        <button onClick={onNext} className="bg-brand-primary text-white px-8 py-3.5 rounded-full text-[10px] font-bold tracking-widest hover:bg-brand-secondary transition-all">
          NEXT SECTION <i className="fas fa-arrow-right ml-2"></i>
        </button>
      </div>

      <h1 className="text-4xl md:text-6xl font-serif text-brand-primary mb-6 tracking-tighter">The Collection</h1>
      <p className="text-slate-500 mb-16 text-lg font-light italic">Choose your assigned silhouette and explore the unique selling points.</p>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        {products.map(product => (
          <div 
            key={product.id}
            onClick={() => setSelected(product)}
            className="group bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-xl transition-all cursor-pointer border border-brand-primary/5 flex flex-col"
          >
            <div className="h-64 relative overflow-hidden">
              <img src={product.image} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" alt={product.name} />
              <div className="absolute inset-0 bg-brand-primary/5 group-hover:bg-transparent transition-colors"></div>
            </div>
            <div className="p-6 flex-grow flex flex-col justify-between">
              <h3 
                onClick={(e) => {
                  e.stopPropagation();
                  window.open(product.url, '_blank');
                }}
                className="text-lg font-serif text-brand-primary mb-4 leading-tight hover:text-brand-secondary transition-colors underline decoration-brand-secondary/30 underline-offset-4"
              >
                {product.name}
              </h3>
              <div className="space-y-3">
                <div className="text-[9px] font-black uppercase text-brand-secondary tracking-widest">Available Colors:</div>
                <div className="flex flex-wrap gap-1.5">
                  {product.colors.map(c => (
                    <span key={c} className="bg-brand-primary/5 px-2.5 py-1 rounded-full text-[9px] font-bold text-brand-primary uppercase tracking-wider">{c}</span>
                  ))}
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {selected && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-brand-dark/40 backdrop-blur-md">
          <div className="bg-brand-bg rounded-[3rem] max-w-4xl w-full overflow-hidden shadow-2xl animate-slide-up flex flex-col md:flex-row max-h-[90vh]">
            <div className="md:w-1/2 h-64 md:h-auto overflow-hidden">
              <img src={selected.image} className="w-full h-full object-cover" alt={selected.name} />
            </div>
            <div className="md:w-1/2 p-8 md:p-12 overflow-y-auto">
              <div className="flex justify-between items-start mb-8">
                <h2 className="text-3xl font-serif text-brand-primary tracking-tighter leading-tight">{selected.name}</h2>
                <button onClick={() => setSelected(null)} className="text-brand-primary/40 hover:text-brand-primary transition-colors p-2">
                  <i className="fas fa-times text-xl"></i>
                </button>
              </div>

              <div className="space-y-10">
                <section>
                  <h4 className="text-[9px] font-black uppercase text-brand-secondary tracking-[0.3em] mb-4">Key Selling Points</h4>
                  <ul className="space-y-4">
                    {selected.sellingPoints.map((point, idx) => (
                      <li key={idx} className="flex items-start gap-3">
                        <i className="fas fa-check text-brand-secondary text-[10px] mt-1.5"></i>
                        <span className="text-slate-600 text-base leading-relaxed font-light italic">{point}</span>
                      </li>
                    ))}
                  </ul>
                </section>

                <div className="pt-6 space-y-3">
                  <a 
                    href={selected.url}
                    target="_blank"
                    className="block w-full text-center bg-brand-primary text-white py-4 rounded-full font-bold uppercase tracking-widest text-[10px] shadow-lg hover:bg-brand-secondary transition-all"
                  >
                    View Official Product Page
                  </a>
                  <button 
                    onClick={() => { setSelected(null); onNext(); }}
                    className="w-full text-brand-primary font-bold uppercase tracking-widest text-[9px] hover:text-brand-secondary transition-colors"
                  >
                    Continue to Next Section
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SectionProducts;

import React from 'react';
import { ActiveSection } from '../types';

interface GlobalNavProps {
  active: ActiveSection;
  onNavigate: (section: ActiveSection) => void;
  isMultiColor: boolean;
}

const GlobalNav: React.FC<GlobalNavProps> = ({ active, onNavigate, isMultiColor }) => {
  const sections: { id: ActiveSection; label: string }[] = [
    { id: 'goals', label: 'Goals' },
    { id: 'products', label: 'Products' },
    ...(isMultiColor ? [{ id: 'multicolor' as ActiveSection, label: 'Spectrum' }] : []),
    { id: 'structure', label: 'Structure' },
    { id: 'hooks', label: 'Inspo' },
    { id: 'brand', label: 'Story' },
  ];

  return (
    <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[90] w-[90%] max-w-2xl">
      <div className="bg-brand-dark/90 backdrop-blur-xl rounded-full p-2 flex justify-between items-center shadow-2xl border border-white/10">
        {sections.map((s) => (
          <button
            key={s.id}
            onClick={() => onNavigate(s.id)}
            className={`flex-1 px-3 py-3 rounded-full text-[9px] font-bold uppercase tracking-widest transition-all ${
              active === s.id 
              ? 'bg-brand-secondary text-white' 
              : 'text-white/40 hover:text-white'
            }`}
          >
            {s.label}
          </button>
        ))}
      </div>
    </div>
  );
};

export default GlobalNav;

