import React from 'react';
import { ActiveSection } from '../types';

interface GlobalNavProps {
  active: ActiveSection;
  onNavigate: (section: ActiveSection) => void;
}

const GlobalNav: React.FC<GlobalNavProps> = ({ active, onNavigate }) => {
  const sections: { id: ActiveSection; label: string }[] = [
    { id: 'requirement', label: 'Rule' },
    { id: 'products', label: 'Choice' },
    { id: 'structure', label: 'Video' },
    { id: 'hooks', label: 'Hook' },
    { id: 'cases', label: 'Inspo' },
    { id: 'brand', label: 'Story' },
  ];

  return (
    <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[140] w-[95%] max-w-2xl">
      <div className="bg-brand-dark/90 backdrop-blur-xl rounded-full p-2 flex justify-between items-center shadow-2xl border border-white/10">
        {sections.map((s) => (
          <button
            key={s.id}
            onClick={() => onNavigate(s.id)}
            className={`flex-1 px-2 py-3 rounded-full text-[8px] font-bold uppercase tracking-widest transition-all ${
              active === s.id 
              ? 'bg-brand-secondary text-white' 
              : 'text-white/40 hover:text-white'
            }`}
          >
            {s.label}
          </button>
        ))}
      </div>
    </div>
