                <h1 className="text-6xl md:text-9xl font-black font-brand text-white mb-8 tracking-widest">COSY ISLAND</h1>
                <p className="text-white/80 max-w-2xl mx-auto text-lg font-light italic leading-relaxed mb-10">
                  {currentData.description}
                </p>
                <div>
                  <button 
                    onClick={() => setActiveSection('requirement')}
