      <footer className="bg-brand-dark text-white py-20 border-t border-white/5">
        <div className="container mx-auto text-center px-6">
          <h2 className="text-2xl font-black font-brand mb-8 tracking-widest uppercase">COSY ISLAND</h2>
          <div className="flex flex-col md:flex-row justify-center gap-4 md:gap-12 text-[10px] font-bold uppercase tracking-[0.4em] text-white/30">
            <span>Cosy with an 'S'</span>
            <span>Effortless Comfort</span>
            <span>{content.common.website}</span>
          </div>
          <p className="mt-12 text-white/10 text-[10px] uppercase tracking-widest">© 2026 COSY ISLAND Official</p>
