import React, { useState } from 'react';
import Header from './components/Header';
import GlobalNav from './components/GlobalNav';
import SectionRequirement from './components/sections/SectionRequirement';
import SectionProducts from './components/sections/SectionProducts';
import SectionStructure from './components/sections/SectionStructure';
import SectionHooks from './components/sections/SectionHooks';
import SectionCases from './components/sections/SectionCases';
import SectionBrand from './components/sections/SectionBrand';
import { ActiveSection, CampaignSeason } from './types';
import { CONTENT } from './data';

const App: React.FC = () => {
  const [activeSeason, setActiveSeason] = useState<CampaignSeason>('SS26');
  const [activeSection, setActiveSection] = useState<ActiveSection>('home');

  const content = CONTENT;
  const currentData = activeSeason === 'SS26' ? content.multiColor : content.singleColor;
  const labels = content.common.labels;

  const navigateTo = (next: ActiveSection) => {
    setActiveSection(next);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const renderSection = () => {
    switch (activeSection) {
      case 'requirement': 
        return <SectionRequirement data={currentData.requirement} labels={labels} onBack={() => setActiveSection('home')} onNext={() => navigateTo('products')} />;
      case 'products': 
        return <SectionProducts products={currentData.products} labels={labels} onBack={() => setActiveSection('home')} onNavigate={navigateTo} onNextStep={() => navigateTo('structure')} />;
      case 'structure': 
        return <SectionStructure data={currentData.structure} labels={labels} onBack={() => setActiveSection('home')} onNext={() => navigateTo('hooks')} />;
      case 'hooks': 
        return <SectionHooks hooks={currentData.hooks} labels={labels} onBack={() => setActiveSection('home')} onNext={() => navigateTo('cases')} />;
      case 'cases': 
        return <SectionCases data={currentData.cases} labels={labels} onBack={() => setActiveSection('home')} onNext={() => navigateTo('brand')} />;
      case 'brand': 
        return <SectionBrand labels={labels} onBack={() => setActiveSection('home')} />;
      default: return (
        <div className="animate-slide-up">
          {/* Full-width Hero Banner Banner */}
          <div className="w-full relative h-[70vh] overflow-hidden bg-brand-dark">
            <img 
              src={currentData.heroImage} 
              className="absolute inset-0 w-full h-full object-cover opacity-60"
              alt="COSY ISLAND Banner"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-brand-dark/90 via-transparent to-brand-dark/20"></div>
            <div className="absolute inset-0 flex flex-col justify-center items-center text-center px-6">
              <span className="text-brand-secondary font-bold tracking-[0.6em] uppercase text-xs mb-6 drop-shadow-lg">
                {currentData.label}
              </span>
              <h1 className="text-6xl md:text-9xl font-black font-brand text-white mb-10 tracking-[0.2em] drop-shadow-2xl">COSY ISLAND</h1>
              <p className="text-white/90 max-w-4xl mx-auto text-xl md:text-2xl font-light italic leading-relaxed mb-12 drop-shadow-md">
                {currentData.description}
              </p>
              <div>
                <button 
                  onClick={() => setActiveSection('requirement')}
                  className="bg-brand-primary text-white px-20 py-6 rounded-full font-bold text-sm hover:bg-brand-secondary transition-all transform hover:-translate-y-1 shadow-2xl uppercase tracking-[0.4em]"
                >
                  {labels.explore}
                </button>
              </div>
            </div>
          </div>

          {/* Centered 6-Section Grid with Straight Edges (No Radius) */}
          <div className="max-w-7xl mx-auto px-6 py-24 flex justify-center">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10 w-full">
              <SectionCard num="01" title={labels.rules} subtitle="Collaboration" onClick={() => setActiveSection('requirement')} />
              <SectionCard num="02" title={labels.choice} subtitle="Catalog" onClick={() => setActiveSection('products')} />
              <SectionCard num="03" title={labels.framework} subtitle="Shooting" onClick={() => setActiveSection('structure')} />
              <SectionCard num="04" title={labels.hooks} subtitle="Creativity" onClick={() => setActiveSection('hooks')} />
              <SectionCard num="05" title={labels.inspiration} subtitle="Community" onClick={() => setActiveSection('cases')} />
              <SectionCard num="06" title={labels.story} subtitle="Identity" onClick={() => setActiveSection('brand')} />
            </div>
          </div>
        </div>
      );
    }
  };

  return (
    <div className="min-h-screen bg-brand-bg">
      <Header 
        season={activeSeason} 
        onSeasonChange={(s) => { setActiveSeason(s); setActiveSection('home'); }} 
        onHome={() => setActiveSection('home')}
      />

      {activeSection !== 'home' && (
        <GlobalNav active={activeSection} onNavigate={setActiveSection} labels={labels} />
      )}

      <main className="pb-32">
        {renderSection()}
      </main>

      <footer className="bg-brand-dark text-white py-24 border-t border-white/5">
        <div className="container mx-auto text-center px-6">
          <h2 className="text-3xl font-black font-brand mb-10 tracking-widest uppercase text-brand-secondary">COSY ISLAND</h2>
          <div className="flex flex-col md:flex-row justify-center gap-6 md:gap-16 text-[12px] font-bold uppercase tracking-[0.5em] text-white/40">
            <span>Cosy with an 'S'</span>
            <span>Effortless Comfort</span>
            <span>{content.common.website}</span>
          </div>
          <p className="mt-16 text-white/10 text-[10px] uppercase tracking-widest">© 2026 COSY ISLAND Official</p>
        </div>
      </footer>
    </div>
  );
