  return (
    <div className="max-w-[1400px] mx-auto px-6 py-20 animate-slide-up">
      <div className="flex justify-between items-center mb-16">
        <button onClick={onBack} className="text-brand-primary/50 hover:text-brand-primary font-bold text-[11px] tracking-widest transition-all uppercase">
          <i className="fas fa-arrow-left mr-2"></i> {labels.home}
        </button>
        <button onClick={onNextStep} className="bg-brand-primary text-white px-12 py-4 rounded-full text-[11px] font-black tracking-widest hover:bg-brand-secondary transition-all uppercase shadow-lg">
          {labels.framework} <i className="fas fa-arrow-right ml-2"></i>
        </button>
      </div>

      <h1 className="text-6xl md:text-8xl font-serif text-brand-primary mb-16 tracking-tighter leading-none">{labels.choice}</h1>

      {/* Sub-section: This Month's Selection */}
      <div className="mb-20">
        <h2 className="text-xs font-black uppercase tracking-[0.6em] text-brand-secondary mb-10 border-l-4 border-brand-secondary pl-6">This Month’s Selection</h2>
