          {currentMonth.map(p => <ProductCard key={p.id} product={p} />)}
        </div>
      </div>

      {/* Sub-section: Previous Selections */}
      {pastSelections.length > 0 && (
        <div className="mb-20">
          <h2 className="text-xs font-black uppercase tracking-[0.6em] text-brand-primary/40 mb-10 border-l-4 border-brand-primary/10 pl-6">Previous Selections</h2>
