        <button onClick={onNextStep} className="bg-brand-primary text-white px-12 py-4 rounded-full text-[11px] font-black tracking-widest hover:bg-brand-secondary transition-all uppercase shadow-lg">
          {labels.framework} <i className="fas fa-arrow-right ml-2"></i>
        </button>
      </div>

      <h1 className="text-6xl md:text-8xl font-serif text-brand-primary mb-16 tracking-tighter leading-none">{labels.choice}</h1>

      <div className="mb-20">
        <h2 className="text-xs font-black uppercase tracking-[0.6em] text-brand-secondary mb-10 border-l-4 border-brand-secondary pl-6">This Month’s Selection</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10">
          {currentMonth.map(p => (
            <ProductCard 
              key={p.id} 
              product={p} 
              onSelect={handleProductSelect} 
            />
          ))}
        </div>
      </div>

      {pastSelections.length > 0 && (
        <div className="mb-20">
          <h2 className="text-xs font-black uppercase tracking-[0.6em] text-brand-primary/40 mb-10 border-l-4 border-brand-primary/10 pl-6">Previous Selections</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10">
            {pastSelections.map(p => (
              <ProductCard 
                key={p.id} 
                product={p} 
                onSelect={handleProductSelect} 
              />
            ))}
          </div>
        </div>
      )}

      {selected && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-brand-dark/50 backdrop-blur-md">
          <div className="bg-brand-bg rounded-none max-w-5xl w-full overflow-hidden shadow-2xl animate-slide-up flex flex-col max-h-[85vh] border border-white/20">

            {/* Modal Header */}
            <div className="flex flex-col md:flex-row h-auto md:h-[25%] overflow-hidden bg-brand-white border-b border-brand-primary/10">
              <div className="md:w-[30%] bg-brand-beige/10 p-6 flex items-center justify-center overflow-hidden border-r border-brand-primary/5">
                <img src={selected.image} className="max-w-full max-h-32 object-contain" alt={selected.name} />
              </div>
              <div className="md:w-[70%] p-8 flex flex-col justify-center relative">
                <button onClick={() => setSelected(null)} className="absolute top-6 right-6 text-brand-primary/30 hover:text-brand-primary transition-colors text-3xl">
                  <i className="fas fa-times"></i>
                </button>
                <h2 onClick={() => window.open(selected.url, '_blank')} className="text-3xl font-serif text-brand-primary tracking-tighter cursor-pointer hover:text-brand-secondary transition-colors mb-2">
                  {toTitleCase(selected.name)} <i className="fas fa-external-link-alt text-base opacity-20 ml-2"></i>
                </h2>
                <div className="flex flex-wrap gap-2.5 mb-2">
                  {selected.colors.map(c => <span key={c} className="bg-brand-primary/5 px-4 py-1.5 rounded-full text-[10px] font-black text-brand-primary uppercase tracking-widest">{c}</span>)}
                </div>
                {selected.firstShowColor && (
                  <p className="text-brand-secondary text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                    <i className="fas fa-info-circle"></i> Instruction: First show the <span className="underline">{selected.firstShowColor}</span> color.
                  </p>
                )}
              </div>
            </div>

            {/* Modal Content Tabs */}
            <div className="bg-brand-white border-b border-brand-primary/10 p-4 flex gap-4 overflow-x-auto">
               <button 
                  onClick={() => setActiveTab('sellingPoints')}
                  className={`px-8 py-3 font-black text-[10px] uppercase tracking-widest border transition-all ${activeTab === 'sellingPoints' ? 'bg-brand-primary text-white border-brand-primary' : 'bg-transparent text-brand-primary border-brand-primary/20 hover:border-brand-primary'}`}
               >
                  Selling Points
               </button>
               <button 
                  onClick={() => setActiveTab('cases')}
                  className={`px-8 py-3 font-black text-[10px] uppercase tracking-widest border transition-all ${activeTab === 'cases' ? 'bg-brand-primary text-white border-brand-primary' : 'bg-transparent text-brand-primary border-brand-primary/20 hover:border-brand-primary'}`}
               >
                  Classic Cases
               </button>
               <button 
                  onClick={() => {
                    setSelected(null);
                    onNavigate('structure');
                  }}
                  className="px-8 py-3 font-black text-[10px] uppercase tracking-widest border border-brand-primary/20 text-brand-primary hover:bg-brand-primary hover:text-white transition-all ml-auto"
               >
                  Video Framework <i className="fas fa-external-link-alt ml-2 opacity-50"></i>
               </button>
            </div>

            <div className="flex-grow p-12 overflow-y-auto bg-brand-white">
              {activeTab === 'sellingPoints' && (
                <div className="grid grid-cols-1 gap-12 animate-slide-up">
                  {selected.sellingPoints.map((point, idx) => {
                    const parts = point.split(':');
                    const hasTitle = parts.length > 1;
                    const title = hasTitle ? parts[0].trim() : '';
                    const body = hasTitle ? parts.slice(1).join(':').trim() : point.trim();

                    return (
                      <div key={idx} className="flex gap-8 items-start group">
                        <span className="text-4xl font-serif text-brand-primary italic opacity-10 leading-none min-w-[3rem]">0{idx + 1}</span>
                        <div className="flex-grow space-y-2">
                          {hasTitle && (
                            <h5 className="text-brand-primary font-black uppercase text-xs tracking-widest">{title}</h5>
                          )}
                          <p className={`text-slate-600 text-lg font-light italic leading-relaxed ${!hasTitle ? 'text-brand-primary/80 font-bold' : ''}`}>
                            {body}
                          </p>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}

              {activeTab === 'cases' && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 animate-slide-up">
                  {(selected.detailCases || []).map((item, idx) => (
                    <div key={idx} className="card-standard">
                      <div className="aspect-[3/4] overflow-hidden relative group">
                         <img src={item.imageUrl} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" alt={item.title} />
                         <div className="absolute inset-0 bg-black/20 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                            <i className="fas fa-play text-white text-3xl"></i>
                         </div>
                      </div>
                      <div className="p-4">
                        <h4 className="font-serif text-brand-primary text-lg">{item.title}</h4>
                        <p className="text-slate-400 text-[10px] uppercase tracking-widest">@{item.author}</p>
                      </div>
                    </div>
                  ))}
                  {(!selected.detailCases || selected.detailCases.length === 0) && (
                    <div className="col-span-full py-20 text-center text-slate-400 italic">No specific cases found for this model.</div>
                  )}
                </div>
              )}
            </div>

            <div className="p-10 border-t border-brand-primary/10 bg-brand-beige/10 flex flex-col md:flex-row gap-6">
              {isMultiColor ? (
                 <button onClick={() => { setSelected(null); onNextStep(); }} className="flex-1 bg-brand-primary text-white py-6 font-black uppercase tracking-[0.4em] text-[11px] hover:bg-brand-secondary transition-all shadow-xl">
                    {labels.framework}
                 </button>
              ) : (
                <>
                  <button onClick={() => { setSelected(null); onNavigate('cases'); }} className="flex-1 bg-brand-dark text-white py-6 font-black uppercase tracking-[0.4em] text-[11px] hover:bg-black transition-all shadow-xl">
                    Global Inspiration Cases
                  </button>
                  <button onClick={() => { setSelected(null); onNextStep(); }} className="flex-1 bg-brand-white border border-brand-primary/20 text-brand-primary py-6 font-black uppercase tracking-[0.4em] text-[11px] hover:bg-brand-primary hover:text-white transition-all shadow-xl">
                    Ready to Start
                  </button>
                </>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SectionProducts;

export type CampaignSeason = 'SS25' | 'SS26';
export type ActiveSection = 'home' | 'onboarding' | 'platform' | 'campaignType' | 'requirement' | 'products' | 'structure' | 'hooks' | 'cases' | 'brand' | 'media';
export type Platform = 'IG' | 'YT';

export interface ProductFeature {
  id: string;
  name: string;
  image: string;
  colors: string[];
  sellingPoints: string[];
  url: string;
  isPastSelection?: boolean;
  firstShowColor?: string;
  detailCases?: CaseStudy[];
}

export interface CaseStudy {
  title: string;
  description: string;
  imageUrl: string;
  videoUrl?: string;
  author: string;
}

export interface HookItem {
  title: string;
  description: string;
  imageUrl: string;
  author: string;
}

export interface RequirementData {
  goals: string;
  flows: { title: string; desc: string }[];
  ig?: {
    reelReqs: { text: string; status: 'do' | 'dont' }[];
    carouselReqs: { text: string; status: 'do' | 'dont' }[];
    captionReqs: {
      ad: string;
      mentions: string[];
      exclusivity: string;
      direction: string;
    };
  };
  yt?: {
    dedicated: { text: string; status: 'do' | 'dont' }[];
    integrated: { text: string; status: 'do' | 'dont' }[];
    captionReqs: {
      links: string;
      tags: string[];
    };
  };
}

export interface StructureStep {
  title: string;
  desc: string;
  examples: string[];
}

export interface CampaignData {
  label: string;
  id: string;
  heroImage: string;
  description: string;
  requirement: RequirementData;
  products: ProductFeature[];
  structure: {
    intro: string;
    steps: StructureStep[];
    reminder1: { title: string; points: string[]; images: string[] };
    reminder2: { title: string; desc: string; images: string[] };
  };
  hooks: HookItem[];
  cases: {
    intro: string;
    items: CaseStudy[];
    tips: string[];
  };
  mediaAssets: {
    reviews: string[];
    modeling: string[];
    certifications: string[];
  };
}

export interface CampaignContent {
  singleColor: CampaignData;
  multiColor: CampaignData;
  common: {
    brandName: string;
    website: string;
    instagram: string;
    seasonalColors: string[];
    labels: { [key: string]: string };
  };
}

