import React, { useState } from 'react';
import Header from './components/Header';
import GlobalNav from './components/GlobalNav';
import SectionRequirement from './components/sections/SectionRequirement';
import SectionProducts from './components/sections/SectionProducts';
import SectionStructure from './components/sections/SectionStructure';
import SectionHooks from './components/sections/SectionHooks';
import SectionCases from './components/sections/SectionCases';
import SectionBrand from './components/sections/SectionBrand';
import SectionMedia from './components/sections/SectionMedia';
import { ActiveSection, CampaignSeason, Platform } from './types';
import { CONTENT } from './data';

const App: React.FC = () => {
  const [activeSeason, setActiveSeason] = useState<CampaignSeason>('SS26');
  const [activeSection, setActiveSection] = useState<ActiveSection>('home');
  const [selectedPlatform, setSelectedPlatform] = useState<Platform | null>(null);
  const [isOnboarding, setIsOnboarding] = useState(false);

  const content = CONTENT;
  const currentData = activeSeason === 'SS26' ? content.multiColor : content.singleColor;
  const labels = content.common.labels;

  const navigateTo = (next: ActiveSection) => {
    setActiveSection(next);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const resetToHome = () => {
    setActiveSection('home');
    setIsOnboarding(false);
    setSelectedPlatform(null);
  };

  const startOnboarding = () => {
    setIsOnboarding(true);
    navigateTo('platform');
  };

  const renderSection = () => {
    switch (activeSection) {
      case 'platform':
        return (
          <div className="max-w-4xl mx-auto px-6 py-32 text-center animate-slide-up">
            <h2 className="text-brand-secondary font-black uppercase tracking-[0.6em] text-xs mb-10">Step 1</h2>
            <h1 className="text-6xl font-serif text-brand-primary mb-16 tracking-tighter">Choose Your Platform</h1>
            <div className="flex flex-col md:flex-row gap-8 justify-center">
              <button 
                onClick={() => { setSelectedPlatform('IG'); navigateTo('campaignType'); }}
                className="flex-1 bg-brand-white p-12 border-2 border-brand-primary/10 hover:border-brand-primary transition-all rounded-none group"
              >
                <i className="fab fa-instagram text-6xl text-brand-secondary mb-6 group-hover:scale-110 transition-transform"></i>
                <p className="font-black uppercase tracking-widest text-brand-primary">Instagram</p>
              </button>
              <button 
                onClick={() => { setSelectedPlatform('YT'); navigateTo('campaignType'); }}
                className="flex-1 bg-brand-white p-12 border-2 border-brand-primary/10 hover:border-brand-primary transition-all rounded-none group"
              >
                <i className="fab fa-youtube text-6xl text-brand-secondary mb-6 group-hover:scale-110 transition-transform"></i>
                <p className="font-black uppercase tracking-widest text-brand-primary">YouTube</p>
              </button>
            </div>
          </div>
        );

      case 'campaignType':
        return (
          <div className="max-w-4xl mx-auto px-6 py-32 text-center animate-slide-up">
            <h2 className="text-brand-secondary font-black uppercase tracking-[0.6em] text-xs mb-10">Step 2</h2>
            <h1 className="text-6xl font-serif text-brand-primary mb-16 tracking-tighter">Select Collaboration Theme</h1>
            <div className="flex flex-col md:flex-row gap-8 justify-center">
              <button 
                onClick={() => { setActiveSeason('SS25'); navigateTo('requirement'); }}
                className="flex-1 bg-brand-white p-12 border-2 border-brand-primary/10 hover:border-brand-primary transition-all rounded-none"
              >
                <p className="font-black uppercase tracking-widest text-brand-primary">Monochrome (SS25)</p>
              </button>
              <button 
                onClick={() => { setActiveSeason('SS26'); navigateTo('requirement'); }}
                className="flex-1 bg-brand-white p-12 border-2 border-brand-primary/10 hover:border-brand-primary transition-all rounded-none"
              >
                <p className="font-black uppercase tracking-widest text-brand-primary">Spectrum (SS26)</p>
              </button>
            </div>
          </div>
        );

      case 'requirement': 
        return <SectionRequirement data={currentData.requirement} platform={selectedPlatform || 'IG'} structureReminders={currentData.structure} labels={labels} onBack={() => navigateTo('campaignType')} onNext={() => navigateTo('products')} />;
      case 'products': 
        return <SectionProducts products={currentData.products} isMultiColor={activeSeason === 'SS26'} labels={labels} onBack={() => navigateTo('requirement')} onNavigate={navigateTo} onNextStep={() => navigateTo('structure')} />;
      case 'structure': 
        return <SectionStructure data={currentData.structure} labels={labels} onBack={() => navigateTo('products')} onNext={() => navigateTo('hooks')} />;
      case 'hooks': 
        return <SectionHooks hooks={currentData.hooks} labels={labels} onBack={() => navigateTo('structure')} onNext={() => navigateTo('cases')} />;
      case 'cases': 
        return <SectionCases data={currentData.cases} labels={labels} onBack={() => navigateTo('hooks')} onNext={() => navigateTo('brand')} />;
      case 'brand': 
        return <SectionBrand labels={labels} onBack={() => navigateTo('cases')} onNext={() => navigateTo('media')} />;
      case 'media':
        return <SectionMedia data={currentData.mediaAssets} labels={labels} onBack={() => navigateTo('brand')} />;

      default: return (
        <div className="animate-slide-up">
          <div className="w-full relative h-[60vh] overflow-hidden bg-brand-dark">
            <img src={currentData.heroImage} className="absolute inset-0 w-full h-full object-cover opacity-60" alt="COSY ISLAND" />
            <div className="absolute inset-0 bg-gradient-to-t from-brand-dark/90 via-transparent to-brand-dark/20"></div>

            {/* Seasonal Swatches */}
            <div className="absolute bottom-8 right-8 flex gap-3">
              {content.common.seasonalColors.map(color => (
                <div key={color} style={{ backgroundColor: color }} className="w-8 h-12 shadow-xl border border-white/20"></div>
              ))}
            </div>

            <div className="absolute inset-0 flex flex-col justify-center items-center text-center px-6">
              <h1 className="text-6xl md:text-8xl font-black font-brand text-white mb-8 tracking-[0.2em]">COSY ISLAND</h1>
              <p className="text-white/90 max-w-4xl mx-auto text-lg md:text-xl font-light italic leading-relaxed mb-12">
                "We aspire to create a cosy island for your feet."
              </p>
              <div className="flex flex-col md:flex-row gap-6 items-center">
                <button 
                  onClick={startOnboarding}
                  className="bg-brand-primary text-white px-16 py-6 rounded-none font-bold text-sm hover:bg-brand-secondary transition-all transform hover:-translate-y-1 shadow-2xl uppercase tracking-[0.4em] min-w-[300px]"
                >
                  First Time to Collaborate
                </button>
                <button 
                  onClick={() => navigateTo('campaignType')}
                  className="bg-white/10 text-white border border-white/20 px-12 py-5 rounded-none font-bold text-xs hover:bg-white/20 transition-all uppercase tracking-[0.4em]"
                >
                  Not First Time
                </button>
              </div>
            </div>
          </div>
        </div>
      );
    }
  };

  return (
    <div className="min-h-screen bg-brand-bg font-sans">
      <Header 
        season={activeSeason} 
        onSeasonChange={(s) => { setActiveSeason(s); navigateTo('home'); }} 
        onHome={resetToHome}
      />

      {activeSection !== 'home' && (
        <GlobalNav active={activeSection} onNavigate={navigateTo} labels={labels} />
      )}

      <main className="pb-32">
        {renderSection()}
      </main>

      <footer className="bg-brand-dark text-white py-24 border-t border-white/5">
        <div className="container mx-auto text-center px-6">
          <h2 className="text-2xl font-black font-brand mb-10 tracking-widest uppercase text-brand-secondary">COSY ISLAND</h2>
          <div className="flex flex-col md:flex-row justify-center gap-6 md:gap-16 text-[11px] font-bold uppercase tracking-[0.5em] text-white/40">
            <span>Cosy with an 'S'</span>
            <span>Effortless Comfort</span>
            <span>{content.common.website}</span>
          </div>
          <p className="mt-16 text-white/10 text-[10px] uppercase tracking-widest">© 2026 COSY ISLAND Official</p>
        </div>
      </footer>
    </div>
  );
};

